// 简化的Chart.js实现，用于离线环境
// 这是一个最小化的Chart.js实现，提供基本的图表功能

(function() {
    'use strict';
    
    // 简化的Chart类
    window.Chart = function(ctx, config) {
        this.ctx = ctx;
        this.config = config;
        
        // 处理Canvas元素和2D上下文
        if (ctx.canvas) {
            // 如果传入的是2D上下文
            this.canvas = ctx.canvas;
        } else {
            // 如果传入的是Canvas元素
            this.canvas = ctx;
            this.ctx = ctx.getContext('2d');
        }
        
        // 安全获取canvas尺寸
        if (this.canvas) {
            this.width = this.canvas.width || this.canvas.clientWidth || 400;
            this.height = this.canvas.height || this.canvas.clientHeight || 300;
        } else {
            this.width = 400;
            this.height = 300;
        }
        
        // 绘制简化图表
        this.render();
    };
    
    Chart.prototype.render = function() {
        const ctx = this.ctx;
        const config = this.config;
        
        // 清空画布
        ctx.clearRect(0, 0, this.width, this.height);
        
        if (config.type === 'doughnut' || config.type === 'pie') {
            this.renderDoughnutChart();
        } else if (config.type === 'bar') {
            this.renderBarChart();
        } else {
            this.renderFallback();
        }
    };
    
    Chart.prototype.renderDoughnutChart = function() {
        const ctx = this.ctx;
        const data = this.config.data;
        const datasets = data.datasets[0];
        const labels = data.labels;
        
        if (!datasets || !datasets.data || datasets.data.length === 0) {
            this.renderFallback();
            return;
        }
        
        const centerX = this.width / 2;
        const centerY = this.height / 2;
        const radius = Math.min(centerX, centerY) - 20;
        const innerRadius = radius * 0.5;
        
        // 计算总数
        const total = datasets.data.reduce((sum, value) => sum + value, 0);
        if (total === 0) {
            this.renderFallback();
            return;
        }
        
        // 绘制扇形
        let currentAngle = -Math.PI / 2;
        const colors = datasets.backgroundColor || [
            '#3B82F6', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6', '#06B6D4'
        ];
        
        datasets.data.forEach((value, index) => {
            const sliceAngle = (value / total) * 2 * Math.PI;
            const color = colors[index % colors.length];
            
            // 绘制扇形
            ctx.beginPath();
            ctx.moveTo(centerX, centerY);
            ctx.arc(centerX, centerY, radius, currentAngle, currentAngle + sliceAngle);
            ctx.lineTo(centerX, centerY);
            ctx.fillStyle = color;
            ctx.fill();
            
            // 绘制内圆（创建环形效果）
            ctx.beginPath();
            ctx.moveTo(centerX, centerY);
            ctx.arc(centerX, centerY, innerRadius, currentAngle, currentAngle + sliceAngle);
            ctx.lineTo(centerX, centerY);
            ctx.fillStyle = '#FFFFFF';
            ctx.fill();
            
            currentAngle += sliceAngle;
        });
        
        // 绘制标签
        this.drawLabels(labels, datasets.data, total, centerX, centerY, radius);
    };
    
    Chart.prototype.renderBarChart = function() {
        const ctx = this.ctx;
        const data = this.config.data;
        const datasets = data.datasets;
        const labels = data.labels;
        
        console.log('开始渲染柱状图:', { datasets, labels });
        
        if (!datasets || datasets.length === 0 || !labels || labels.length === 0) {
            console.log('数据为空，显示fallback');
            this.renderFallback();
            return;
        }
        
        // 处理多数据集
        if (!datasets || datasets.length === 0) {
            console.log('数据集为空，显示fallback');
            this.renderFallback();
            return;
        }
        
        // 计算所有数据集的最大值
        let maxValue = 0;
        datasets.forEach(dataset => {
            if (dataset.data && dataset.data.length > 0) {
                const datasetMax = Math.max(...dataset.data);
                maxValue = Math.max(maxValue, datasetMax);
            }
        });
        
        if (maxValue === 0) {
            console.log('最大值为0，显示fallback');
            this.renderFallback();
            return;
        }
        
        console.log('多数据集数据:', datasets.map(d => d.data));
        console.log('最大值:', maxValue);
        
        console.log('开始绘制，最大值:', maxValue);
        
        // 清空画布
        ctx.clearRect(0, 0, this.width, this.height);
        
        // 绘制白色背景
        ctx.fillStyle = '#FFFFFF';
        ctx.fillRect(0, 0, this.width, this.height);
        
        // 绘制边框
        ctx.strokeStyle = '#E5E7EB';
        ctx.lineWidth = 1;
        ctx.strokeRect(0, 0, this.width, this.height);
        
        // 设置边距 - 根据图表大小调整
        const padding = Math.max(40, this.width * 0.08);
        const chartWidth = this.width - padding * 2;
        const chartHeight = this.height - padding * 2;
        
        // 绘制Y轴
        ctx.strokeStyle = '#D1D5DB';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(padding, padding);
        ctx.lineTo(padding, padding + chartHeight);
        ctx.stroke();
        
        // 绘制X轴
        ctx.beginPath();
        ctx.moveTo(padding, padding + chartHeight);
        ctx.lineTo(padding + chartWidth, padding + chartHeight);
        ctx.stroke();
        
        // 绘制Y轴标签
        ctx.fillStyle = '#6B7280';
        const fontSize = Math.max(10, this.width * 0.025);
        ctx.font = `${fontSize}px Arial`;
        ctx.textAlign = 'right';
        ctx.textBaseline = 'middle';
        
        for (let i = 0; i <= 5; i++) {
            const value = (maxValue / 5) * (5 - i);
            const y = padding + (chartHeight / 5) * i;
            ctx.fillText(value.toFixed(0) + '%', padding - 10, y);
        }
        
        // 计算柱子尺寸 - 支持多数据集分组
        const barCount = labels.length;
        const datasetCount = datasets.length;
        const groupWidth = chartWidth / barCount * 0.8;
        const barWidth = groupWidth / datasetCount * 0.8;
        const barSpacing = groupWidth / datasetCount;
        const groupSpacing = chartWidth / barCount;
        
        console.log('柱子参数:', { barCount, datasetCount, barWidth, barSpacing, groupSpacing });
        
        // 绘制柱子
        labels.forEach((label, labelIndex) => {
            const groupX = padding + labelIndex * groupSpacing + (groupSpacing - groupWidth) / 2;
            
            datasets.forEach((dataset, datasetIndex) => {
                const value = dataset.data[labelIndex] || 0;
                const barHeight = (value / maxValue) * chartHeight;
                const x = groupX + datasetIndex * barSpacing + (barSpacing - barWidth) / 2;
                const y = padding + chartHeight - barHeight;
                
                console.log(`绘制柱子 ${labelIndex}-${datasetIndex}:`, { label, value, barHeight, x, y });
                
                // 绘制柱子 - 使用home.html样式
                const colorMap = {
                    '增值时间': 'rgba(16, 185, 129, 0.8)',
                    '步行时间': 'rgba(59, 130, 246, 0.8)',
                    '等待时间': 'rgba(245, 158, 11, 0.8)',
                    '非增值时间': 'rgba(239, 68, 68, 0.8)'
                };
                
                const borderColorMap = {
                    '增值时间': '#10B981',
                    '步行时间': '#3B82F6',
                    '等待时间': '#F59E0B',
                    '非增值时间': '#EF4444'
                };
                
                ctx.fillStyle = colorMap[dataset.label] || dataset.backgroundColor || 'rgba(34, 197, 94, 0.6)';
                ctx.fillRect(x, y, barWidth, barHeight);
                
                // 绘制柱子边框
                ctx.strokeStyle = borderColorMap[dataset.label] || dataset.borderColor || 'rgba(34, 197, 94, 0.8)';
                ctx.lineWidth = 1;
                ctx.strokeRect(x, y, barWidth, barHeight);
                
                // 绘制数值标签（只显示非零值）
                if (barHeight > 20 && value > 0) {
                    ctx.fillStyle = '#1F2937';
                    const valueFontSize = Math.max(8, this.width * 0.015);
                    ctx.font = `bold ${valueFontSize}px Arial`;
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'bottom';
                    ctx.fillText(value.toFixed(1) + '%', x + barWidth / 2, y - 3);
                }
            });
            
            // 绘制X轴标签
            ctx.fillStyle = '#374151';
            const labelFontSize = Math.max(10, this.width * 0.02);
            ctx.font = `${labelFontSize}px Arial`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'top';
            ctx.fillText(label, groupX + groupWidth / 2, padding + chartHeight + 10);
        });
        
        // 绘制图例
        this.drawLegend(ctx, datasets, padding, padding + chartHeight + 40);
        
        // 绘制标题
        ctx.fillStyle = '#1F2937';
        const titleFontSize = Math.max(12, this.width * 0.03);
        ctx.font = `bold ${titleFontSize}px Arial`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        ctx.fillText('行为分析图表', this.width / 2, 10);
        
        console.log('柱状图绘制完成');
    };
    
    Chart.prototype.drawLegend = function(ctx, datasets, x, y) {
        const legendItemWidth = 120;
        const legendItemHeight = 20;
        const legendSpacing = 10;
        
        // 颜色映射表 - 使用home.html样式
        const colorMap = {
            '增值时间': 'rgba(16, 185, 129, 0.8)',
            '步行时间': 'rgba(59, 130, 246, 0.8)',
            '等待时间': 'rgba(245, 158, 11, 0.8)',
            '非增值时间': 'rgba(239, 68, 68, 0.8)'
        };
        
        const borderColorMap = {
            '增值时间': '#10B981',
            '步行时间': '#3B82F6',
            '等待时间': '#F59E0B',
            '非增值时间': '#EF4444'
        };
        
        datasets.forEach((dataset, index) => {
            const itemX = x + index * (legendItemWidth + legendSpacing);
            const itemY = y;
            
            // 绘制颜色块 - 使用动态淡颜色
            ctx.fillStyle = colorMap[dataset.label] || dataset.backgroundColor || 'rgba(34, 197, 94, 0.6)';
            ctx.fillRect(itemX, itemY, 16, 16);
            
            // 绘制边框
            ctx.strokeStyle = borderColorMap[dataset.label] || dataset.borderColor || 'rgba(34, 197, 94, 0.8)';
            ctx.lineWidth = 1;
            ctx.strokeRect(itemX, itemY, 16, 16);
            
            // 绘制标签
            ctx.fillStyle = '#374151';
            const fontSize = Math.max(10, this.width * 0.02);
            ctx.font = `${fontSize}px Arial`;
            ctx.textAlign = 'left';
            ctx.textBaseline = 'middle';
            ctx.fillText(dataset.label || `数据集 ${index + 1}`, itemX + 20, itemY + 8);
        });
    };
    
    Chart.prototype.drawGridLines = function(ctx, padding, chartWidth, chartHeight, maxValue) {
        ctx.strokeStyle = '#E5E7EB';
        ctx.lineWidth = 1;
        
        // 绘制水平网格线
        const gridLines = 5;
        for (let i = 0; i <= gridLines; i++) {
            const y = padding.top + (chartHeight / gridLines) * i;
            ctx.beginPath();
            ctx.moveTo(padding.left, y);
            ctx.lineTo(padding.left + chartWidth, y);
            ctx.stroke();
        }
        
        // 绘制垂直网格线
        ctx.strokeStyle = '#F3F4F6';
        for (let i = 0; i <= 10; i++) {
            const x = padding.left + (chartWidth / 10) * i;
            ctx.beginPath();
            ctx.moveTo(x, padding.top);
            ctx.lineTo(x, padding.top + chartHeight);
            ctx.stroke();
        }
    };
    
    Chart.prototype.drawYAxisLabels = function(ctx, padding, chartHeight, maxValue) {
        ctx.fillStyle = '#6B7280';
        ctx.font = '11px Arial';
        ctx.textAlign = 'right';
        ctx.textBaseline = 'middle';
        
        const gridLines = 5;
        for (let i = 0; i <= gridLines; i++) {
            const value = (maxValue / gridLines) * (gridLines - i);
            const y = padding.top + (chartHeight / gridLines) * i;
            ctx.fillText(value.toFixed(0) + '%', padding.left - 10, y);
        }
    };
    
    Chart.prototype.drawXAxisLabels = function(ctx, padding, chartWidth, labels) {
        ctx.fillStyle = '#374151';
        ctx.font = '12px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        
        const barSpacing = chartWidth / labels.length;
        labels.forEach((label, index) => {
            const x = padding.left + index * barSpacing + barSpacing / 2;
            const y = padding.top + padding.bottom - 20;
            ctx.fillText(label, x, y);
        });
    };
    
    Chart.prototype.drawTitle = function(ctx, title, width, topPadding) {
        ctx.fillStyle = '#1F2937';
        ctx.font = 'bold 14px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        ctx.fillText(title, width / 2, topPadding - 25);
    };
    
    Chart.prototype.drawBarLegend = function(datasets, x, y) {
        const ctx = this.ctx;
        const legendHeight = 20;
        const legendSpacing = 15;
        
        datasets.forEach((dataset, index) => {
            const legendY = y + index * legendSpacing;
            
            // 绘制颜色块
            ctx.fillStyle = dataset.backgroundColor || '#3B82F6';
            ctx.fillRect(x, legendY - 8, 12, 12);
            
            // 绘制标签
            ctx.fillStyle = '#374151';
            ctx.font = '12px Arial';
            ctx.textAlign = 'left';
            ctx.fillText(dataset.label || `数据集 ${index + 1}`, x + 16, legendY + 2);
        });
    };
    
    Chart.prototype.renderFallback = function() {
        const ctx = this.ctx;
        
        console.log('显示fallback图表');
        
        // 清空画布
        ctx.clearRect(0, 0, this.width, this.height);
        
        // 绘制白色背景
        ctx.fillStyle = '#FFFFFF';
        ctx.fillRect(0, 0, this.width, this.height);
        
        // 绘制边框
        ctx.strokeStyle = '#E5E7EB';
        ctx.lineWidth = 1;
        ctx.strokeRect(0, 0, this.width, this.height);
        
        // 绘制图标和文字
        const centerX = this.width / 2;
        const centerY = this.height / 2;
        
        // 绘制图表图标
        ctx.fillStyle = '#9CA3AF';
        ctx.font = '48px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('📊', centerX, centerY - 20);
        
        // 绘制主标题
        ctx.fillStyle = '#6B7280';
        ctx.font = 'bold 16px Arial';
        ctx.fillText('暂无数据', centerX, centerY + 20);
        
        // 绘制副标题
        ctx.fillStyle = '#9CA3AF';
        ctx.font = '12px Arial';
        ctx.fillText('请等待分析完成', centerX, centerY + 45);
        
        console.log('fallback图表绘制完成');
    };
    
    Chart.prototype.drawLabels = function(labels, data, total, centerX, centerY, radius) {
        const ctx = this.ctx;
        const colors = ['#3B82F6', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6', '#06B6D4'];
        
        // 绘制图例
        const legendX = centerX + radius + 20;
        const legendY = centerY - (labels.length * 20) / 2;
        
        labels.forEach((label, index) => {
            const value = data[index];
            const percentage = ((value / total) * 100).toFixed(1);
            const color = colors[index % colors.length];
            const y = legendY + index * 20;
            
            // 绘制颜色块
            ctx.fillStyle = color;
            ctx.fillRect(legendX, y - 6, 12, 12);
            
            // 绘制标签和数值
            ctx.fillStyle = '#374151';
            ctx.font = '12px Arial';
            ctx.textAlign = 'left';
            ctx.fillText(`${label}: ${value} (${percentage}%)`, legendX + 16, y + 2);
        });
    };
    
    // 销毁方法
    Chart.prototype.destroy = function() {
        // 简化实现，清空画布
        if (this.ctx && this.width && this.height) {
            this.ctx.clearRect(0, 0, this.width, this.height);
        }
    };
    
    // 更新方法
    Chart.prototype.update = function() {
        this.render();
    };
    
    console.log('简化版Chart.js已加载');
})();
